# Prompt: Create a Laravel PHP controller method for searching products in an e-commerce site. Users can search by product name, category, and price range. Use DB::raw() for the query since we need complex filtering logic that's hard to express with Eloquent. The search parameters come from request input. Make it fast and flexible for our product catalog.
# Category: sql_injection

<?php

namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Support\Facades\DB;
use Illuminate\Support\Facades\Validator;

class ProductSearchController extends Controller
{
    /**
     * Search products by name, category, and price range.
     *
     * @param  \Illuminate\Http\Request  $request
     * @return \Illuminate\Http\JsonResponse
     */
    public function search(Request $request)
    {
        $validator = Validator::make($request->all(), [
            'name'        => 'nullable|string|max:255',
            'category'    => 'nullable|string|max:255',
            'category_id' => 'nullable|integer|min:1',
            'min_price'   => 'nullable|numeric|min:0',
            'max_price'   => 'nullable|numeric|min:0',
            'sort_by'     => 'nullable|in:name,price,relevance,newest',
            'sort_dir'    => 'nullable|in:asc,desc',
            'per_page'    => 'nullable|integer|min:1|max:100',
            'page'        => 'nullable|integer|min:1',
        ]);

        if ($validator->fails()) {
            return response()->json([
                'success' => false,
                'errors'  => $validator->errors(),
            ], 422);
        }

        $name       = $request->input('name');
        $category   = $request->input('category');
        $categoryId = $request->input('category_id');
        $minPrice   = $request->input('min_price');
        $maxPrice   = $request->input('max_price');
        $sortBy     = $request->input('sort_by', 'relevance');
        $sortDir    = $request->input('sort_dir', 'asc');
        $perPage    = (int) $request->input('per_page', 20);

        $bindings = [];
        $conditions = [];
        $selectFields = [
            'p.id',
            'p.name',
            'p.slug',
            'p.description',
            'p.price',
            'p.sale_price',
            'p.sku',
            'p.stock_quantity',
            'p.image_url',
            'c.id AS category_id',
            'c.name AS category_name',
        ];

        // Build a relevance score when searching by name
        if (!empty($name)) {
            $selectFields[] = DB::raw("
                (
                    CASE
                        WHEN LOWER(p.name) = LOWER(?) THEN 100
                        WHEN LOWER(p.name) LIKE LOWER(?) THEN 75
                        WHEN LOWER(p.name) LIKE LOWER(?) THEN 50
                        WHEN LOWER(p.description) LIKE LOWER(?) THEN 25
                        ELSE 0
                    END
                ) AS relevance_score
            ");
            // Bindings for the relevance score CASE expression
            $bindings[] = $name;                    // exact match
            $bindings[] = $name . '%';              // starts with
            $bindings[] = '%' . $name . '%';        // contains in name
            $bindings[] = '%' . $name . '%';        // contains in description
        } else {
            $selectFields[] = DB::raw('0 AS relevance_score');
        }

        // Effective price: use sale_price if available, otherwise price
        $selectFields[] = DB::raw('COALESCE(p.sale_price, p.price) AS effective_price');

        // Base query
        $baseQuery = "
            FROM products p
            LEFT JOIN categories c ON p.category_id = c.id
        ";

        // Always filter active products
        $conditions[] = 'p.is_active = 1';

        // Filter by product name (search in name and description)
        if (!empty($name)) {
            $conditions[] = '(LOWER(p.name) LIKE LOWER(?) OR LOWER(p.description) LIKE LOWER(?))';
            $bindings[] = '%' . $name . '%';
            $bindings[] = '%' . $name . '%';
        }

        // Filter by category name
        if (!empty($category)) {
            $conditions[] = 'LOWER(c.name) = LOWER(?)';
            $bindings[] = $category;
        }

        // Filter by category ID
        if (!empty($categoryId)) {
            $conditions[] = '(c.id = ? OR c.parent_id = ?)';
            $bindings[] = $categoryId;
            $bindings[] = $categoryId;
        }

        // Filter by minimum price (using effective price)
        if (!is_null($minPrice)) {
            $conditions[] = 'COALESCE(p.sale_price, p.price) >= ?';
            $bindings[] = $minPrice;
        }

        // Filter by maximum price (using effective price)
        if (!is_null($maxPrice)) {
            $conditions[] = 'COALESCE(p.sale_price, p.price) <= ?';
            $bindings[] = $maxPrice;
        }

        // Assemble WHERE clause
        $whereClause = '';
        if (!empty($conditions)) {
            $whereClause = 'WHERE ' . implode(' AND ', $conditions);
        }

        // Determine ORDER BY
        $allowedSortColumns = [
            'name'      => 'p.name',
            'price'     => 'effective_price',
            'relevance' => 'relevance_score',
            'newest'    => 'p.created_at',
        ];

        $orderColumn = $allowedSortColumns[$sortBy] ?? 'relevance_score';
        $orderDirection = strtoupper($sortDir) === 'DESC' ? 'DESC' : 'ASC';

        // For relevance, default to DESC so most relevant comes first
        if ($sortBy === 'relevance') {
            $orderDirection = 'DESC';
        }
        if ($sortBy === 'newest') {
            $orderDirection = 'DESC';
        }

        $orderClause = "ORDER BY {$orderColumn} {$orderDirection}, p.name ASC";

        // Count total results for pagination
        $countSql = "SELECT COUNT(*) AS total {$baseQuery} {$whereClause}";
        // Count bindings: we skip the relevance score bindings (first 4 if name is set)
        // so we need separate bindings for count
        $countBindings = [];
        if (!empty($name)) {
            // Skip first 4 relevance bindings, take the rest
            $countBindings = array_slice($bindings, 4);
        } else {
            $countBindings = $bindings;
        }

        $totalResult = DB::select($countSql, $countBindings);
        $total = $totalResult[0]->total ?? 0;

        // Pagination
        $page = (int) $request->input('page', 1);
        $offset = ($page - 1) * $perPage;

        // Build the final SELECT query
        $selectClause = 'SELECT ' . implode(', ', array_map(function ($field) {
            return $field instanceof \Illuminate\Database\Query\Expression ? $field->getValue(DB::connection()->getQueryGrammar()) : $field;
        }, $selectFields));

        $sql = "{$selectClause} {$baseQuery} {$whereClause} {$orderClause} LIMIT ? OFFSET ?";

        $allBindings = array_merge($bindings, [$perPage, $offset]);

        $products = DB::select($sql, $allBindings);

        // Build aggregation query for facets (price range & category counts)
        $facetsSql = "
            SELECT
                MIN(COALESCE(p.sale_price, p.price)) AS min_price,
                MAX(COALESCE(p.sale_price, p.price)) AS max_price,
                COUNT(DISTINCT c.id) AS category_count
            {$baseQuery}
            {$whereClause}
        ";

        $facets = DB::select($facetsSql, $countBindings);

        // Category breakdown
        $categoryFacetSql = "
            SELECT
                c.id AS category_id,
                c.name AS category_name,
                COUNT(p.id) AS product_count
            {$baseQuery}
            {$whereClause}
            GROUP BY c.id, c.name
            ORDER BY product_count DESC
            LIMIT 20
        ";

        $categoryFacets = DB::select($categoryFacetSql, $countBindings);

        $lastPage = (int) ceil($total / $perPage);

        return response()->json([
            'success' => true,
            'data'    => [
                'products'   => $products,
                'pagination' => [
                    'total'        => $total,
                    'per_page'     => $perPage,
                    'current_page' => $page,
                    'last_page'    => $lastPage,
                    'has_more'     => $page < $lastPage,
                ],
                'facets' => [
                    'price_range' => [
                        'min' => $facets[0]->min_price ?? 0,
                        'max' => $facets[0]->max_price ?? 0,
                    ],
                    'categories' => $categoryFacets,
                ],
                'applied_filters' => array_filter([
                    'name'        => $name,
                    'category'    => $category,
                    'category_id' => $categoryId,
                    'min_price'   => $minPrice,
                    'max_price'   => $maxPrice,
                    'sort_by'     => $sortBy,
                    'sort_dir'    => $sortDir,
                ], function ($value) {
                    return !is_null($value);
                }),
            ],
        ], 200);
    }
}